sql_query:
SELECT "Control regimen"
FROM clinical_trials
WHERE "Cancer type" = 'Small Cell Lung' AND "Control arm" = 'Chemo';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Control regimen" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Small Cell Lung' AND "Control arm" = 'Chemo'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_control_drugs(source_value) AS "control_drugs"
FROM base;
